        .tabs {
            display: flex;
            border-bottom: 2px solid var(--border);
            margin-bottom: 1.5rem;
        }

        .tab-btn {
            padding: 0.75rem 1.5rem;
            background: none;
            border: none;
            border-bottom: 2px solid transparent;
            cursor: pointer;
            font-weight: 600;
            color: var(--muted);
            flex: 1;
            text-align: center;
            transition: all 0.2s;
        }

        .tab-btn.active {
            color: var(--primary);
            border-bottom-color: var(--primary);
        }

        .tab-content { display: none; }
        .tab-content.active { display: block; }

        .chart-container {
            height: 200px;
            position: relative;
            margin-top: 1rem;
        }

        /* Simple CSS Bar Chart */
        .bar-group {
            display: flex;
            align-items: flex-end;
            height: 100%;
            padding-top: 2rem;
            gap: 1rem;
        }
        .bar {
            flex: 1;
            background: var(--primary);
            position: relative;
            transition: height 0.3s ease;
            border-radius: 4px 4px 0 0;
            min-height: 0;
        }
        .bar span {
            position: absolute;
            bottom: 0;
            left: 0;
            width: 100%;
            text-align: center;
            font-size: 0.75rem;
            color: var(--muted);
            display: none;
        }
        .bar:hover span { display: block; }
        .bar.principal { background: var(--accent); }
        .bar.interest { background: var(--danger); }

        .note {
            font-size: 0.85rem;
            color: var(--muted);
            font-style: italic;
            margin-top: 1rem;
        }
    </style>
</head>
